import {ref, computed} from ‘@vue/reactivity’

const count = ref(0)
const doubleCount = computed(() => count.value * 2)

console.log(count.value, doubleCount.value) // 0, 1

count.value++

console.log(count.value, doubleCount.value) // 1, 2
